  updateGift() {
    const g = this.selectedGiftForEdit;
    if (!g.name || !g.description || !g.ticketPrice || !g.donorId || !g.categoryId || !g.image) {
      alert(g.image + g.categoryId + g.donorId)
      alert("נא למלא את כל שדות החובה לפני העדכון");
      this.errorMessage = "נא למלא את כל שדות החובה לפני העדכון";
      return; // עוצר כאן ולא ממשיך לקריאת ה-API
    }
    alert(g.name);
    this.errorMessage = '';
    this.giftService.updateGift(this.selectedGiftForEdit.id, this.selectedGiftForEdit).subscribe({
      next: (res) => {
        console.log('המתנה עודכנה בהצלחה!');
        this.displayEditDialog = false;
        this.loadGifts(); // רענון הרשימה
      },
      error: (err) => {
        if (err.error && err.error.errors) {
          const errors = err.error.errors;
          this.errorMessage = Object.values(errors).flat().join(', ');
        } else {
          this.errorMessage = 'אירעה שגיאה בשמירת המתנה.';
        }
        this.cdr.detectChanges();
      }
    });
  }

  // חיפוש לפי שם
  sortByName(event: Event) {
    const value = (event.target as HTMLInputElement).value.trim();

    if (!value) {
      this.loadGifts(); // טוען את כל המתנות מחדש
      return;
    }

    this.giftService.sortByName(value).subscribe(data => {
      this.allGifts = data; // העדכון צריך להיות במערך הראשי
      this.first = 0;        // מתחילים מהעמוד הראשון
      this.updatePage();     // חותכים ל-pagedGifts
      this.cdr.detectChanges();
    });
  }

  // חיפוש לפי שם תורם
  sortByDonorName(event: Event) {
    const value = (event.target as HTMLInputElement).value.trim();

    if (!value) {
      this.loadGifts();
      return;
    }

    this.giftService.sortByDonorName(value).subscribe(data => {
      this.allGifts = data;
      this.first = 0;
      this.updatePage();
      this.cdr.detectChanges();
    });
  }
  orderByCategory(categoryId: number) {
    if (!categoryId) {
      // אם לא נבחרה קטגוריה – טוענים את כל המתנות
      this.loadGifts();
      return;
    }

    this.giftService.orderByCategory(categoryId).subscribe(data => {
      this.allGifts = data;
      this.first = 0;       // מתחילים מהעמוד הראשון
      this.updatePage();    // מעדכנים את pagedGifts
      this.cdr.detectChanges();
    });
  }
